  "TPR57_3_01": ["Welches Tier kommt als nächstes? Katze, Hund, Fisch, Katze, Hund, Fisch, Katze, Hund, ?", "Drei Tiere wiederholen sich in derselben Reihenfolge.", ["Katze", "Fisch", "Hund", "Vogel"], "Das Muster ist die Wiederholung von Katze, Hund und Fisch. Nach der Katze folgt der Hund dem Fisch."],
  "TPR57_3_02": ["Was kommt als nächstes? 1, 1, 2, 2, 3, 3, 4, 4, ?", "Jede Zahl erscheint zweimal. Welche neue Nummer kommt als nächstes?", ["4", "3", "5", "6"], "Jede Zahl erscheint zweimal: 1,1, 2,2, 3,3, 4,4. Als nächstes kommt 5."],
  "TPR57_3_03": ["Was kommt als nächstes? Apfel, Banane, Kirsche, Apfel, Banane, Kirsche, Apfel, Banane, ?", "Drei Früchte werden in derselben Reihenfolge wiederholt.", ["Apfel", "Banane", "Kirsche", "Traube"], "Das Muster ist die Wiederholung von Apfel, Banane und Kirsche. Nach der Banane kommt die Kirsche."],
  "TPR57_3_04": ["Was kommt als nächstes? Rot, Gelb, Blau, Rot, Gelb, Blau, Rot, Gelb, ?", "Drei Farben kehren immer in derselben Reihenfolge zurück.", ["Rot", "Gelb", "Grün", "Blau"], "Das Muster besteht aus sich wiederholenden Farben Rot, Gelb und Blau. Nach Gelb kommt Blau."],
  "TPR57_3_05": ["Welcher Form folgt es? Dreieck, Kreis, Quadrat, Dreieck, Kreis, Quadrat, Dreieck, Kreis, ?", "Drei Formen werden in derselben Reihenfolge wiederholt.", ["Quadratisch", "Dreieck", "Kreis", "Rechteck"], "Das Muster ist ein sich wiederholendes Dreieck, Kreis, Quadrat. Nach dem Kreis kommt das Quadrat."],
  "TPR57_3_06": ["Was kommt als nächstes? 2, 4, 6, 2, 4, 6, 2, 4, ?", "Drei Zahlen werden wiederholt.", ["2", "8", "6", "4"], "Das Muster besteht aus 2, 4, 6 Wiederholungen. Nach 2, 4 kommt 6."],
  "TPR57_3_07": ["Was kommt als nächstes? Klein, Mittel, Groß, Klein, Mittel, Groß, Klein, Mittel, ?", "Drei Größen werden vom kleinsten zum größten wiederholt.", ["Klein", "Groß", "Umwelt", "Der Kleine"], "Das Muster ist klein, mittel, groß und wiederholt sich. Nach der Mitte kommt die Große."],
  "TPR57_3_08": ["Was kommt als nächstes? Gehen, Laufen, Springen, Gehen, Laufen, Springen, Gehen, Laufen, ?", "Drei Aktionen werden in derselben Reihenfolge wiederholt.", ["Gehen", "Schritt", "Lauf weg", "springen"], "Das Muster ist Gehen, Laufen, Springen, das sich wiederholt. Nach dem Laufen kommt der Sprung."],
  "TPR57_3_09": ["Welcher Tag kommt nach Samstag?", "Denken Sie der Reihe nach über die Wochentage nach.", ["Sonntag", "Montag", "Freitag", "Dienstag"], "Tage gehen: Freitag, Samstag, Sonntag. Nach dem Samstag kommt der Sonntag."],
  "TPR57_3_10": ["Was kommt als nächstes? A, B, A, C, A, B, A, C, A, B, A, ?", "Finden Sie die sich wiederholende Gruppe: A, B, A, C.", ["A", "B", "C", "d"], "Das Muster ist A, B, A, C und wiederholt sich. Nach A, B, A kommt C."],
  "TPR57_3_11": ["Was kommt als nächstes? 1, 2, 3, 2, 1, 2, 3, 2, 1, 2, 3, ?", "Die Zahlen steigen und fallen dann wieder. Pass auf den Sprung auf!", ["1", "2", "4", "3"], "Das Muster wiederholt sich 1, 2, 3, 2. Nach 1, 2, 3 kommt 2."],
  "TPR57_3_12": ["Was kommt als nächstes? Sonne, Wolke, Regen, Sonne, Wolke, Regen, Sonne, Wolke, ?", "Drei Worte über das Wetter werden wiederholt.", ["Sonne", "Schnee", "Wolke", "Es regnet"], "Das Muster ist die Wiederholung von Sonne, Wolke und Regen. Nach Cloud kommt Regen."],
  "TPR57_3_13": ["Was kommt als nächstes? Groß, größer, am höchsten, groß, größer, am höchsten, groß, größer, ?", "Drei Größen werden wiederholt.", ["Der Höchste", "Groß", "Höher", "Kurz"], "Das Muster wiederholt sich „Tall, Taller, Tallest“. Nach dem Höchsten kommt das Höchste."],
  "TPR57_3_14": ["Welche Zahl kommt als nächstes? 1, 3, 5, 1, 3, 5, 1, 3, ?", "Drei Zahlen werden wiederholt.", ["1", "5", "3", "7"], "Das Muster besteht aus 1, 3, 5 Wiederholungen. Nach 1, 3 kommt 5."],
  "TPR57_3_15": ["Was kommt als nächstes? Essen, schlafen, spielen, essen, schlafen, spielen, essen, schlafen, ?", "Drei Aktivitäten werden wiederholt.", ["Essen", "schlafen", "Spielen Sie es", "Ruhe dich aus"], "Das Muster ist Essen, Schlafen, Spielen, das sich wiederholt. Nach dem Schlafen kommt das Spielen."],
  "TPR57_3_16": ["Was kommt als nächstes? Rot, Rot, Blau, Blau, Grün, Grün, Rot, Rot, Blau, Blau, ?", "Jede Farbe erscheint zweimal, dann beginnt die nächste Farbe.", ["Rot", "Blau", "Grün", "Gelb"], "Das Muster ist rot, rot, blau, blau, grün, grün und wiederholt sich. Nach Blau folgt Blau Grün."],
  "TPR57_3_17": ["Welche Zahl kommt als nächstes? Eins, zwei, drei, vier, fünf, sechs, ?", "Zählen Sie einfach weiter!", ["Opt", "Sieben", "Neun", "Zehn"], "Wir zählen: Eins, zwei, drei, vier, fünf, sechs, sieben."],
  "TPR57_3_18": ["Was kommt als nächstes? Stein, Papier, Schere, Stein, Papier, Schere, Stein, Papier, ?", "Drei Wörter werden wiederholt.", ["Papier", "Stein", "Stift", "Schere"], "Das Muster ist die Wiederholung von Stein, Papier und Schere. Nach dem Papier kommt die Schere."],
  "TPR57_3_19": ["Was kommt als nächstes? Stern, Mond, Stern, Stern, Mond, Stern, Stern, Mond, ?", "Was kommt nach jedem Mond immer als nächstes?", ["Stern", "Mond", "Sonne", "Wolke"], "Das Muster ist die Wiederholung von Stern, Mond und Stern. Nach dem Mond kommt der Stern."],
  "TPR57_3_20": ["Was kommt als nächstes? 1, 2, 1, 1, 2, 1, 1, 2, ?", "Was kommt nach jeweils 2 immer als nächstes?", ["2", "3", "1", "4"], "Das Muster wiederholt sich 1, 2, 1. Nach 2 kommt 1."],

  // ==========================================================================
