  "TNR57_1_01": ["Was kommt als nächstes? 1, 2, 3, 4, ?", "Zählen Sie von eins bis eins.", ["5", "6", "3", "7"], "Wir zählen von 1 bis 1: 1, 2, 3, 4, 5. Die nächste Zahl ist 5."],
  "TNR57_1_02": ["Was kommt als nächstes? 3, 4, 5, 6, ?", "Zählen Sie weiter von eins bis eins!", ["5", "8", "6", "7"], "Wir zählen von 1 bis 1: 3, 4, 5, 6, 7. Die nächste Zahl ist 7."],
  "TNR57_1_03": ["Was kommt als nächstes? 5, 6, 7, 8, ?", "Welche Zahl kommt nach 8?", ["7", "9", "10", "8"], "Wir zählen von 1 bis 1: 5, 6, 7, 8, 9. Die nächste Zahl ist 9."],
  "TNR57_1_04": ["Was kommt als nächstes? 2, 4, 6, 8, ?", "Wir überspringen jedes Mal eine Nummer. Zählen Sie von 2 bis 2!", ["9", "12", "10", "11"], "Wir zählen von 2 bis 2: 2, 4, 6, 8, 10. Die nächste Zahl ist 10."],
  "TNR57_1_05": ["Was kommt als nächstes? 1, 3, 5, 7, ?", "Wir überspringen jedes Mal eine Zahl: 1, überspringe 2, 3, überspringe 4, 5 ...", ["8", "10", "11", "9"], "Wir zählen in Zweierschritten (ungerade Zahlen): 1, 3, 5, 7, 9. Die nächste Zahl ist 9."],
  "TNR57_1_06": ["Was kommt als nächstes? 4, 6, 8, 10, ?", "Zählen Sie von 2 bis 2. Wie viel ist 10 plus 2?", ["12", "11", "14", "9"], "Wir zählen von 2 bis 2: 4, 6, 8, 10, 12. Die nächste Zahl ist 12."],
  "TNR57_1_07": ["Was kommt als nächstes? 6, 7, 8, 9, ?", "Zählen Sie weiter! Was kommt nach 9?", ["11", "10", "12", "8"], "Wir zählen von 1 bis 1: 6, 7, 8, 9, 10. Die nächste Zahl ist 10."],
  "TNR57_1_08": ["Was kommt als nächstes? 2, 3, 4, 5, ?", "Zählen Sie von eins bis eins.", ["7", "5", "6", "8"], "Wir zählen von 1 bis 1: 2, 3, 4, 5, 6. Die nächste Zahl ist 6."],
  "TNR57_1_09": ["Was kommt als nächstes? 7, 8, 9, 10, ?", "Welche Zahl kommt nach 10?", ["12", "10", "9", "11"], "Wir zählen von 1 bis 1: 7, 8, 9, 10, 11. Die nächste Zahl ist 11."],
  "TNR57_1_10": ["Was kommt als nächstes? 6, 8, 10, 12, ?", "Wir springen jedes Mal von 2 auf 2!", ["14", "13", "15", "16"], "Wir zählen in Zweierschritten: 6, 8, 10, 12, 14. Die nächste Zahl ist 14."],
  "TNR57_1_11": ["Was kommt als nächstes? 10, 11, 12, 13, ?", "Zählen Sie weiter von eins bis eins!", ["15", "14", "12", "16"], "Wir zählen von 1 bis 1: 10, 11, 12, 13, 14. Die nächste Zahl ist 14."],
  "TNR57_1_12": ["Welche Zahl fehlt? 1, 2, ?, 4, 5", "Welche Zahl liegt zwischen 2 und 4?", ["6", "7", "3", "0"], "Zählen 1, 2, 3, 4, 5. Die fehlende Zahl ist 3."],
  "TNR57_1_13": ["Was kommt als nächstes? 8, 9, 10, 11, ?", "Welche Zahl kommt nach 11?", ["10", "13", "14", "12"], "Wir zählen von 1 bis 1: 8, 9, 10, 11, 12. Die nächste Zahl ist 12."],
  "TNR57_1_14": ["Was kommt als nächstes? 10, 12, 14, 16, ?", "Wir springen jedes Mal von 2 auf 2!", ["18", "17", "19", "20"], "Wir zählen in Zweierschritten: 10, 12, 14, 16, 18. Die nächste Zahl ist 18."],
  "TNR57_1_15": ["Was kommt als nächstes? 4, 5, 6, 7, ?", "Zählen Sie weiter von eins bis eins!", ["9", "8", "10", "6"], "Wir zählen von 1 bis 1: 4, 5, 6, 7, 8. Die nächste Zahl ist 8."],
  "TNR57_1_16": ["Welche Zahl fehlt? 5, 6, 7, ?, 9", "Welche Zahl liegt zwischen 7 und 9?", ["10", "6", "8", "11"], "Zählen 5, 6, 7, 8, 9. Die fehlende Zahl ist 8."],
  "TNR57_1_17": ["Was kommt als nächstes? 3, 5, 7, 9, ?", "Wir zählen von 2 bis 2. Wie viel ist 9 plus 2?", ["10", "12", "13", "11"], "Wir zählen von 2 bis 2: 3, 5, 7, 9, 11. Die nächste Zahl ist 11."],
  "TNR57_1_18": ["Was kommt als nächstes? 11, 12, 13, 14, ?", "Zählen Sie einfach weiter!", ["15", "16", "14", "17"], "Wir zählen von 1 bis 1: 11, 12, 13, 14, 15. Die nächste Zahl ist 15."],
  "TNR57_1_19": ["Welche Zahl fehlt? 2, 4, ?, 8, 10", "Wir zählen von 2 bis 2. Was liegt zwischen 4 und 8?", ["5", "6", "7", "12"], "Zählen in 2er-Schritten: 2, 4, 6, 8, 10. Die fehlende Zahl ist 6."],
  "TNR57_1_20": ["Was kommt als nächstes? 14, 16, 18, 20, ?", "Zählen Sie von 2 bis 2. Wie viel ist 20 plus 2?", ["21", "23", "22", "24"], "Wir zählen in Zweierschritten: 14, 16, 18, 20, 22. Die nächste Zahl ist 22."],

  // ==========================================================================
