  "TNR57_2_01": ["Zahl von 5 bis 5: 5, 10, 15, 20, ?", "Jedes Mal 5 hinzufügen. Was ist 20 plus 5?", ["25", "30", "22", "21"], "Wir zählen von 5 bis 5: 5, 10, 15, 20, 25. Die nächste Zahl ist 25."],
  "TNR57_2_02": ["Zählen Sie von 10 bis 10: 10, 20, 30, 40, ?", "Jedes Mal 10 hinzufügen. Was ist 40 plus 10?", ["45", "50", "60", "55"], "Wir zählen von 10 bis 10: 10, 20, 30, 40, 50. Die nächste Zahl ist 50."],
  "TNR57_2_03": ["Zurückzählen: 10, 9, 8, 7, ?", "Wir verringern jedes Mal um 1.", ["5", "8", "6", "9"], "Wir zählen rückwärts: 10, 9, 8, 7, 6. Die nächste Zahl ist 6."],
  "TNR57_2_04": ["Zahl von 5 bis 5: 10, 15, 20, 25, ?", "Jedes Mal 5 hinzufügen. Was ist 25 plus 5?", ["28", "35", "25", "30"], "Wir zählen von 5 bis 5: 10, 15, 20, 25, 30. Die nächste Zahl ist 30."],
  "TNR57_2_05": ["Zurückzählen: 5, 4, 3, 2, ?", "Gehen Sie weiter um 1 nach unten!", ["1", "0", "3", "6"], "Wir zählen herunter: 5, 4, 3, 2, 1. Die nächste Zahl ist 1."],
  "TNR57_2_06": ["Zählen Sie von 10 bis 10: 20, 30, 40, 50, ?", "Jedes Mal 10 hinzufügen.", ["55", "60", "70", "65"], "Wir zählen von 10 bis 10: 20, 30, 40, 50, 60. Die nächste Zahl ist 60."],
  "TNR57_2_07": ["Zurückzählen: 8, 7, 6, 5, ?", "Gehen Sie weiter um 1 nach unten!", ["3", "6", "4", "5"], "Wir zählen rückwärts: 8, 7, 6, 5, 4. Die nächste Zahl ist 4."],
  "TNR57_2_08": ["Zahl von 5 bis 5: 25, 30, 35, 40, ?", "Jedes Mal 5 hinzufügen. Was ist 40 plus 5?", ["50", "42", "44", "45"], "Wir zählen von 5 bis 5: 25, 30, 35, 40, 45. Die nächste Zahl ist 45."],
  "TNR57_2_09": ["Zählen Sie von 10 bis 10: 30, 40, 50, 60, ?", "Jedes Mal 10 hinzufügen. Was ist 60 plus 10?", ["70", "65", "80", "75"], "Wir zählen von 10 bis 10: 30, 40, 50, 60, 70. Die nächste Zahl ist 70."],
  "TNR57_2_10": ["Von 2 mal 2 rückwärts zählen: 20, 18, 16, 14, ?", "Subtrahiere jedes Mal 2.", ["13", "12", "10", "15"], "Wir zählen von 2 bis 2 zurück: 20, 18, 16, 14, 12. Die nächste Zahl ist 12."],
  "TNR57_2_11": ["Zahl von 5 bis 5: 30, 35, 40, 45, ?", "Jedes Mal 5 hinzufügen.", ["55", "48", "50", "52"], "Wir zählen von 5 bis 5: 30, 35, 40, 45, 50. Die nächste Zahl ist 50."],
  "TNR57_2_12": ["Countdown: 15, 14, 13, 12, ?", "Gehen Sie weiter um 1 nach unten!", ["10", "13", "14", "11"], "Wir zählen zurück: 15, 14, 13, 12, 11. Die nächste Zahl ist 11."],
  "TNR57_2_13": ["Zählen Sie von 10 bis 10: 50, 60, 70, 80, ?", "Jedes Mal 10 hinzufügen.", ["90", "85", "100", "95"], "Wir zählen von 10 bis 10: 50, 60, 70, 80, 90. Die nächste Zahl ist 90."],
  "TNR57_2_14": ["Von 2 mal 2 rückwärts zählen: 10, 8, 6, 4, ?", "Subtrahiere jedes Mal 2.", ["3", "2", "1", "0"], "Wir zählen von 2 bis 2 rückwärts: 10, 8, 6, 4, 2. Die nächste Zahl ist 2."],
  "TNR57_2_15": ["Welche Zahl fehlt? 5, 10, ?, 20, 25", "Wir zählen von 5 bis 5. Was liegt zwischen 10 und 20?", ["12", "18", "15", "14"], "Von 5 bis 5 zählen: 5, 10, 15, 20, 25. Die fehlende Zahl ist 15."],
  "TNR57_2_16": ["Zahl von 5 bis 5: 40, 45, 50, 55, ?", "Jedes Mal 5 hinzufügen.", ["58", "65", "55", "60"], "Wir zählen von 5 bis 5: 40, 45, 50, 55, 60. Die nächste Zahl ist 60."],
  "TNR57_2_17": ["Von 10 bis 10 rückwärts zählen: 30, 20, 10, ?", "Subtrahiere jedes Mal 10.", ["0", "5", "15", "10"], "Wir zählen von 10 bis 10 rückwärts: 30, 20, 10, 0. Die nächste Zahl ist 0."],
  "TNR57_2_18": ["Zählen Sie von 10 bis 10: 40, 50, 60, 70, ?", "Jedes Mal 10 hinzufügen.", ["75", "80", "90", "85"], "Wir zählen von 10 bis 10: 40, 50, 60, 70, 80. Die nächste Zahl ist 80."],
  "TNR57_2_19": ["Welche Zahl fehlt? 10, 20, 30, ?, 50", "Wir zählen von 10 bis 10. Was liegt zwischen 30 und 50?", ["35", "45", "40", "25"], "Zählen bis 10: 10, 20, 30, 40, 50. Die fehlende Zahl ist 40."],
  "TNR57_2_20": ["Von 5 mal 5 rückwärts zählen: 50, 45, 40, 35, ?", "Subtrahiere jedes Mal 5.", ["25", "32", "34", "30"], "Wir zählen von 5 bis 5 zurück: 50, 45, 40, 35, 30. Die nächste Zahl ist 30."],

